'use client';

import { useEffect, useState } from 'react';
import { PieChart } from '@mantine/charts';
import { Card, Center, Loader, SimpleGrid, Tabs, Text, Title } from '@mantine/core';
import { useData } from '@/src/hooks/use-data';

import type { CountsPerCategory, ParsedAnalytics } from '@/src/entities'

import classes from './AnalyticsPanel.module.css';

interface AnalyticsPanelProps {
  selectedUrlId: number | null 
}

type Category = 'browser' | 'os' | 'device';

const SEGMENT_COLORS = ['yellow.5', 'yellow.7', 'gray.4', 'gray.6', 'dark.2', 'dark.4'];

function buildSegments(analytics: CountsPerCategory | null, category: Category): { name: string, value: number, color: string }[]  {
  if (!analytics) return []
  if (!analytics[category]) return []

  const categoryDataToList = []
  for (const [key, value] of Object.entries(analytics[category])) {
    categoryDataToList.push({ name: key, value: value })
  }

  return categoryDataToList
    .sort((a, b) => b['value'] - a['value'])
    .map(({ name, value }, index) => ({
      name,
      value,
      color: SEGMENT_COLORS[index % SEGMENT_COLORS.length],
    }));
}

export function AnalyticsPanel({ selectedUrlId }: AnalyticsPanelProps) {
  const [category, setCategory] = useState<Category>('browser');
  
  const {
    getAnalytics
  } = useData()

  const { data: analytics, error, isLoading } = getAnalytics(selectedUrlId)
  const segments = buildSegments(analytics?.counts_per_category || null, category)

  if (isLoading) {
    return (
      <Card withBorder radius="md" padding="lg">
        <Center className={classes.loading}>
          <Loader color="yellow.5" />
        </Center>
      </Card>
    );
  }

  if (error) {
    return (
      <Card withBorder radius="md" padding="lg">
        <Text c="red" size="sm">
          Failed to load analytics. Please try again later.
        </Text>
      </Card>
    );
  }

  return (
    <Card withBorder radius="md" padding="lg">
      <SimpleGrid cols={2} mb="lg">
        <div>
          <Text c="dimmed" size="sm">
            Total clicks
          </Text>
          <Title order={2}>{analytics?.count || 0}</Title>
        </div>
        <div>
          <Text c="dimmed" size="sm">
            Unique users
          </Text>
          <Title order={2}>{analytics?.unique_user_count || 0}</Title>
        </div>
      </SimpleGrid>

      <Tabs value={category} onChange={(value) => setCategory((value as Category) ?? 'browser')}>
        <Tabs.List mb="lg">
          <Tabs.Tab value="browser">Browser</Tabs.Tab>
          <Tabs.Tab value="os">OS</Tabs.Tab>
          <Tabs.Tab value="device">Device</Tabs.Tab>
        </Tabs.List>

        <Tabs.Panel value="browser">
          {segments.length === 0 ? (
            <Text c="dimmed" size="sm" ta="center" py="xl">
              No analytics data yet.
            </Text>
          ) : (
            <div className={classes.chart}>
              <PieChart data={segments} withLabels withTooltip labelsType="percent" size={220} />
            </div>
          )}
        </Tabs.Panel>
      </Tabs>
    </Card>
  );
}
